// src/pages/LoginPage.js
import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import { useSensor } from '../hooks/useBluetoothSensor';
import './LoginPage.css';

const LoginPage = () => {
    const [username, setUsername] = useState('');
    const [password, setPassword] = useState('');
    const [useFingerprint, setUseFingerprint] = useState(false); // Default to false
    const [localError, setLocalError] = useState('');
    
    const { login, loading, error } = useAuth();
    const { status: sensorStatus } = useSensor();

    // Only enable fingerprint option if sensor is connected
    useEffect(() => {
        if (!sensorStatus.connected) {
            setUseFingerprint(false);
        }
    }, [sensorStatus.connected]);

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLocalError('');

        if (!username) {
            setLocalError('Username is required');
            return;
        }

        if (!useFingerprint && !password) {
            setLocalError('Password is required');
            return;
        }

        const result = await login(username, password, useFingerprint);
        
        if (!result.success) {
            setLocalError(result.error);
        }
    };

    return (
        <div className="login-page">
            <div className="login-container">
                <h2>Login to E-Health System</h2>
                
                {sensorStatus.connected && (
                    <div className="sensor-badge">
                        <span className="sensor-dot"></span>
                        Fingerprint Sensor Connected
                    </div>
                )}

                {(localError || error) && (
                    <div className="error-message">
                        {localError || error}
                    </div>
                )}

                <form onSubmit={handleSubmit}>
                    <div className="form-group">
                        <label htmlFor="username">Username</label>
                        <input
                            type="text"
                            id="username"
                            value={username}
                            onChange={(e) => setUsername(e.target.value)}
                            disabled={loading}
                            placeholder="Enter your username"
                        />
                    </div>

                    {!useFingerprint && (
                        <div className="form-group">
                            <label htmlFor="password">Password</label>
                            <input
                                type="password"
                                id="password"
                                value={password}
                                onChange={(e) => setPassword(e.target.value)}
                                disabled={loading}
                                placeholder="Enter your password"
                            />
                        </div>
                    )}

                    {sensorStatus.connected && (
                        <div className="form-group">
                            <label className="checkbox-label">
                                <input
                                    type="checkbox"
                                    checked={useFingerprint}
                                    onChange={(e) => setUseFingerprint(e.target.checked)}
                                />
                                Use Fingerprint Authentication
                            </label>
                        </div>
                    )}

                    <button 
                        type="submit" 
                        className="btn btn-primary btn-block"
                        disabled={loading}
                    >
                        {loading ? 'Processing...' : 'Login'}
                    </button>
                </form>

                <div className="login-footer">
                    <p>Don't have an account? <a href="/register">Register here</a></p>
                    <p><a href="/">Back to Home</a></p>
                </div>
            </div>
        </div>
    );
};

export default LoginPage;
